module RefModule(
	input [31:0] inALUOut,
	input reset, clk,
	output [31:0] outALUOut
    );reg [31:0] obf_registerALUOut;

	assign outALUOut = obf_registerALUOut;

	always@(posedge clk)
		begin
			if (reset)
				begin
					obf_registerALUOut <= 32'b0;
				end
			else
				begin
					obf_registerALUOut <= inALUOut;
				end
		end

endmodule
